for f in html_files:
    with open(f, "r", encoding="utf-8") as file:
        content = file.read()
    
    if '<div class="wa-tooltip">' in content:
        content = re.sub(r'<div class="wa-widget" id="waWidget">.*?<button id="scrollTopBtn" class="scroll-top" aria-label="Scroll to top">', widget_html, content, flags=re.DOTALL)
